import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatTest {

    private Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
    }

    @Test
    void testParse_DefaultFormat_ReturnsCSVParser() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVParser parser = format.parse(mockReader);
        assertNotNull(parser);
        // Validate that the parser has been created with correct Reader and CSVFormat instance
        assertEquals(format, parser.getFormat());
    }

    @Test
    void testParse_CustomFormat_ReturnsCSVParser() throws IOException {
        CSVFormat customFormat = CSVFormat.DEFAULT.withDelimiter(';').withQuote('\'').withIgnoreEmptyLines(true);
        CSVParser parser = customFormat.parse(mockReader);
        assertNotNull(parser);
        assertEquals(customFormat, parser.getFormat());
    }

    @Test
    void testParse_WithNullReader_ThrowsNullPointerException() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertThrows(NullPointerException.class, () -> format.parse(null));
    }

}
